  "str_1031": "Font Size",
  "str_1032": "<button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize-2)\">A-</button><button class=\"font-sz-btn\" onclick=\"setFontSize(fontSize+2)\">A+</button>",
  "str_1033": "📊 iAccelerator 7 Submission",
  "str_1034": "6-Month Pilot Plan",
  "str_1035": "A focused, evidence-based deployment of the Rinda Initiative in 2 districts of Rwanda — designed to achieve maximum impact within the grant ceiling.",
  "str_1036": "10,000,000 RWF",
  "str_1037": "Total 6-Month Pilot Budget",
  "str_1038": "✅ Within the iAccelerator 7 maximum grant of 10,000,000 RWF",
  "str_1039": "<span>Budget allocation</span><span>100% of grant used</span>",
  "str_1040": "👥 Human Capital — 50% of Budget",
  "str_1041": "Peer Educator Training — 30 Agents",
  "str_1042": "5-day training in HIV counselling, self-test kit use, sign language basics, and safe delivery protocols. 15 agents per district (Gasabo + Huye).",
  "str_1043": "28% · RWF",
  "str_1044": "Agent Stipends — 6 Months",
  "str_1045": "Monthly stipends for 30 peer agents × 6 months. Ensures retention and commitment to delivery schedules.",
  "str_1046": "22% · RWF",
  "str_1047": "📡 USSD &amp; Platform Technology — 25%",
  "str_1048": "USSD Gateway Integration (*775#)",
  "str_1049": "Integration with Rwanda's USSD gateway operators (MTN / Airtel) for live *775# service. Allows reach to 15M+ basic-phone users without internet.",
  "str_1050": "15% · RWF",
  "str_1051": "Platform Hosting, SMS &amp; IVR Services",
  "str_1052": "6-month PWA hosting, SMS notification system, and Interactive Voice Response (IVR) for feature phones. Ensures offline-first access for all users.",
  "str_1053": "10% · RWF",
  "str_1054": "🧪 HIV Self-Test Kits &amp; Supplies — 15%",
  "str_1055": "500 HIV Oral Self-Test Kits",
  "str_1056": "WHO-approved oral HIV self-test kits for anonymous delivery. Enough stock for the 6-month pilot period across both pilot districts.",
  "str_1057": "12% · RWF",
  "str_1058": "Delivery Logistics (Transport)",
  "str_1059": "Moto-taxi and foot delivery costs for discreet kit delivery. Agents use personal transport reimbursed per delivery.",
  "str_1060": "3% · RWF",
  "str_1061": "📈 Monitoring, Evaluation &amp; Community — 10%",
  "str_1062": "M&amp;E Framework &amp; Reporting",
  "str_1063": "Baseline survey, 3-month midline, and 6-month endline evaluation. Tracks testing rates, USSD usage, and negotiation module completion.",
  "str_1064": "6% · RWF",
  "str_1065": "Community Outreach &amp; Youth Events",
  "str_1066": "School and church-based awareness events in pilot districts. Flyer printing, community radio announcements, and youth leader briefings.",
  "str_1067": "4% · RWF",
  "str_1068": "🗓️ 6-Month Timeline",
  "str_1069": "Pilot Execution Roadmap",
  "str_1070": "M1",
  "str_1071": "Month 1 — Setup &amp; Training",
  "str_1072": "Foundation",
  "str_1073": "Recruit and train 30 peer educators in 2 districts. Integrate live *775# USSD gateway. Establish baseline testing rate data.",
  "str_1074": "M2",
  "str_1075": "Month 2 — Soft Launch",
  "str_1076": "First Deliveries",
  "str_1077": "Begin anonymous kit deliveries and USSD service. School awareness events. Monitor first 100 orders and gather user feedback.",
  "str_1078": "M3",
  "str_1079": "Month 3 — Midterm Review",
  "str_1080": "Evaluation &amp; Adjustment",
  "str_1081": "Midline survey. Evaluate USSD adoption. Adjust delivery schedules based on demand. Communities of &gt;50 active USSD users identified for deeper engagement.",
  "str_1082": "M4",
  "str_1083": "Month 4 — Scale Within Districts",
