  "str_1137": "<button class=\"lang-btn active\" data-lang=\"en\">EN</button>\n      <button class=\"lang-btn\" data-lang=\"kin\">KIN</button>",
  "str_1138": "♿ Accessibility",
  "str_1139": "<span>High Contrast</span><label class=\"toggle-switch\"><input type=\"checkbox\" onchange=\"toggleContrast(this.checked)\"><span class=\"toggle-slider\"></span></label>",
  "str_1140": "🏥 SRH Services",
  "str_1141": "Clinics &amp; Care",
  "str_1142": "Find youth-friendly services, book appointments without judgment, and talk to professionals.",
  "str_1143": "<button class=\"c-tab active\" onclick=\"switchTab('locator', this)\">📍 Clinic Locator</button>\n    <button class=\"c-tab\" onclick=\"switchTab('chat', this)\">💬 Chat with HCP</button>\n    <button class=\"c-tab\" onclick=\"switchTab('emergency', this)\">🚨 Call for Help</button>",
  "str_1144": "Showing verified Youth-Friendly Health Centres near you.",
  "str_1145": "Kigali Youth Center",
