  "str_1147": "2.4 km",
  "str_1148": "<button class=\"c-btn primary\" onclick=\"bookApt('Kigali Youth Center')\">Book Appt</button>\n          <a href=\"tel:114\" class=\"c-btn\">Call</a>",
  "str_1149": "Kicukiro Health Clinic",
  "str_1150": "Kicukiro, Kigali<br>PrEP &amp; Family Planning Available",
  "str_1151": "5.1 km",
  "str_1152": "<button class=\"c-btn primary\" onclick=\"bookApt('Kicukiro Health Clinic')\">Book Appt</button>\n          <a href=\"tel:114\" class=\"c-btn\">Call</a>",
  "str_1153": "<h4>Nurse Marie</h4>\n          <span>🟢 Online • Anonymous Chat</span>",
  "str_1154": "Encrypted connection established. Your identity is hidden.",
  "str_1155": "Hello! I'm Nurse Marie. How can I help you today? You can ask me about testing, side effects, or anything related to sexual health.",
  "str_1156": "<input type=\"text\" id=\"chat-input\" placeholder=\"Type a message...\" autocomplete=\"off\" onkeydown=\"if(event.key==='Enter')sendChat()\">\n        <button onclick=\"sendChat()\">📤</button>",
  "str_1157": "GBV &amp; Child Abuse Hotline",
