  "str_1501": "📅 3-Month Overview",
  "str_1502": "<!-- Populated by JS -->",
  "str_1503": "<button class=\"pg-btn\" onclick=\"shiftMonths(-3)\">← Previous 3 Months</button>\n        <button class=\"pg-btn\" onclick=\"shiftMonths(3)\">Next 3 Months →</button>",
  "str_1504": "<strong>Sync to your calendar</strong><br>Download predictions as an .ics file for Google Calendar, iPhone, or Outlook.",
  "str_1505": "Export",
  "str_1506": "📋 Period History",
  "str_1507": "⚠️ Cycle predictions are estimates based on your data. Actual periods may vary by several days. This tool is not a substitute for medical advice. If you notice significant irregularities, please visit a health centre.",
  "str_1508": "How are you feeling today?",
  "str_1509": "Tap symptoms to log them and get personalised health tips.",
  "str_1510": "Cramps",
