  "str_1899": "<input type=\"checkbox\" id=\"consent\" required=\"\" aria-required=\"true\">\n        <span>I understand that this self-test kit is for personal HIV testing and I consent to being contacted for delivery coordination only. <a href=\"knowledge.html\" style=\"color:var(--blue)\">Learn about your rights →</a></span>",
