  "str_1935": "❓ Private · Anonymous",
  "str_1936": "HIV Risk Self-Assessment",
  "str_1937": "5 quick questions → your personal risk level + recommended next steps. 100% private.",
  "str_1938": "Question 1 of 5",
  "str_1939": "When did you last get tested for HIV?",
  "str_1940": "This helps us understand your current testing status.",
  "str_1941": "<button class=\"q-option\" onclick=\"selectOption(1,0,0)\"><span class=\"opt-icon\">✅</span>Within the last 6 months</button>\n        <button class=\"q-option\" onclick=\"selectOption(1,1,1)\"><span class=\"opt-icon\">📅</span>6–12 months ago</button>\n        <button class=\"q-option\" onclick=\"selectOption(1,2,2)\"><span class=\"opt-icon\">⚠️</span>More than 1 year ago</button>\n        <button class=\"q-option\" onclick=\"selectOption(1,3,3)\"><span class=\"opt-icon\">🚨</span>Never been tested</button>",
  "str_1942": "Question 2 of 5",
  "str_1943": "How consistently do you use condoms during sexual activity?",
  "str_1944": "Consistent and correct use is the most effective protection.",
  "str_1945": "<button class=\"q-option\" onclick=\"selectOption(2,0,0)\"><span class=\"opt-icon\">✅</span>Every single time</button>\n        <button class=\"q-option\" onclick=\"selectOption(2,1,1)\"><span class=\"opt-icon\">📊</span>Most of the time</button>\n        <button class=\"q-option\" onclick=\"selectOption(2,2,2)\"><span class=\"opt-icon\">⚠️</span>Sometimes / rarely</button>\n        <button class=\"q-option\" onclick=\"selectOption(2,3,2)\"><span class=\"opt-icon\">🚫</span>Never / not sexually active</button>",
  "str_1946": "Question 3 of 5",
  "str_1947": "Have you ever had difficulty asking your partner to use a condom?",
  "str_1948": "Power dynamics are the #1 barrier for young women in Rwanda (DHS 2025).",
  "str_1949": "<button class=\"q-option\" onclick=\"selectOption(3,0,0)\"><span class=\"opt-icon\">✅</span>No — I feel confident negotiating</button>\n        <button class=\"q-option\" onclick=\"selectOption(3,1,1)\"><span class=\"opt-icon\">😐</span>Sometimes it's difficult</button>\n        <button class=\"q-option\" onclick=\"selectOption(3,2,2)\"><span class=\"opt-icon\">⚠️</span>Yes, I often struggle</button>\n        <button class=\"q-option\" onclick=\"selectOption(3,3,0)\"><span class=\"opt-icon\">➖</span>Not applicable</button>",
  "str_1950": "Question 4 of 5",
  "str_1951": "How would you describe your HIV knowledge?",
  "str_1952": "Only 52.7% of young men 15–24 have comprehensive HIV knowledge (Rwanda DHS 2025, Table 15).",
  "str_1953": "<button class=\"q-option\" onclick=\"selectOption(4,0,0)\"><span class=\"opt-icon\">📚</span>I know how HIV spreads, how to prevent it, and the facts</button>\n        <button class=\"q-option\" onclick=\"selectOption(4,1,1)\"><span class=\"opt-icon\">📖</span>I know the basics but have gaps</button>\n        <button class=\"q-option\" onclick=\"selectOption(4,2,2)\"><span class=\"opt-icon\">❓</span>I'm not very sure about HIV facts</button>\n        <button class=\"q-option\" onclick=\"selectOption(4,3,3)\"><span class=\"opt-icon\">🚨</span>I have very limited knowledge</button>",
  "str_1954": "Question 5 of 5",
  "str_1955": "Do you have access to HIV testing services in your area?",
  "str_1956": "Access gaps are highest in rural and lowest-wealth communities.",
  "str_1957": "<button class=\"q-option\" onclick=\"selectOption(5,0,0)\"><span class=\"opt-icon\">✅</span>Yes — clinic is nearby and accessible</button>\n        <button class=\"q-option\" onclick=\"selectOption(5,1,1)\"><span class=\"opt-icon\">🛣️</span>Yes, but it's far or costly to reach</button>\n        <button class=\"q-option\" onclick=\"selectOption(5,2,2)\"><span class=\"opt-icon\">⚠️</span>No — stigma or distance is a barrier</button>\n        <button class=\"q-option\" onclick=\"selectOption(5,3,2)\"><span class=\"opt-icon\">🚨</span>No accessible testing in my community</button>",
