  "str_2002": "<span>📶 MTN Rwanda</span>\n        <span>🔋 85%</span>",
  "str_2003": "*775# — Rinda Health",
  "str_2004": "<input type=\"text\" id=\"ussd-input\" placeholder=\"Type option (e.g. 1)\" maxlength=\"3\" inputmode=\"numeric\" aria-label=\"Enter USSD menu option\">\n      <button onclick=\"handleInput()\" aria-label=\"Send\">Send</button>",
  "str_2005": "<button class=\"phone-btn\" onclick=\"ussdNavigate('0')\">◀ Back</button>\n      <button class=\"phone-btn primary\" onclick=\"resetUSSD()\">Reset</button>",
  "str_2006": "Why USSD Matters",
  "str_2007": "32.4% HIV Knowledge Gap",
  "str_2008": "Women with no education have only 32.4% HIV knowledge. USSD reaches them in Kinyarwanda, without reading.",
  "str_2009": "Accessible for Visually Impaired Youth",
  "str_2010": "Voice reads every menu option — visually impaired users navigate the full system by sound alone.",
  "str_2011": "Zero Cost, Zero Data",
  "str_2012": "USSD calls are toll-free on the Rinda system. A Rwandan youth in the most remote village can access HIV health services for RWF 0.",
  "str_2013": "<span class=\"nav-icon\">🏠</span>Home",
  "str_2014": "<span class=\"nav-icon\">🏥</span>Care",
