  "str_2018": "Rinda",
  "str_2019": "<a href=\"#problem\">The Problem</a>",
  "str_2020": "<a href=\"#data\">Data</a>",
  "str_2021": "<a href=\"#solution\">Solution</a>",
  "str_2022": "<a href=\"#coverage\">Coverage</a>",
  "str_2023": "<a href=\"#team\">Team</a>",
  "str_2024": "<a href=\"app/index.html\" class=\"nav-cta\" id=\"nav-enter-platform\">Enter Platform →</a>",
  "str_2025": "<span></span><span></span><span></span>",
  "str_2026": "<span>🏆</span> iAccelerator 7 — Rwanda Youth Health Protection",
  "str_2027": "RINDA",
  "str_2028": "<em>\"Rinda\" — Kinyarwanda for \"Protect\"</em>",
  "str_2029": "A <strong>hybrid digital + community platform</strong> attacking the exact statistical gaps in HIV prevention, teenage pregnancy, and reproductive health among Rwanda's youth — backed by 2025 RDHS data.",
  "str_2030": "<a href=\"app/index.html\" class=\"btn-primary\" id=\"hero-cta-platform\">🚀 Enter the Platform</a>\n      <a href=\"#problem\" class=\"btn-secondary\" id=\"hero-cta-data\">📊 See the Data</a>\n      <button class=\"btn-share\" id=\"hero-share-btn\" onclick=\"shareRinda()\" aria-label=\"Share Rinda Initiative\">📤 Share</button>",
  "str_2031": "<span class=\"stat-num\" data-target=\"20\" data-suffix=\"%\">0%</span>\n      <span class=\"stat-label\">Pregnant by Age 19 (RDHS 2025)</span>",
  "str_2032": "<span class=\"stat-num\" data-target=\"81\" data-suffix=\"%\">0%</span>\n      <span class=\"stat-label\">Young Men 15–19 Never Tested</span>",
  "str_2033": "<span class=\"stat-num\" data-target=\"46\" data-suffix=\"%\">0%</span>\n      <span class=\"stat-label\">No Contraception (Sexually Active Unmarried)</span>",
  "str_2034": "The Crisis",
  "str_2035": "Critical Health Gaps in Rwanda's Youth Strategy",
  "str_2036": "Every feature of Rinda directly solves a measurable crisis identified in the 2025 Rwanda Demographic &amp; Health Survey.",
  "str_2037": "Gap 1: The Youth Testing Crisis",
  "str_2038": "Rwanda's testing programs are failing the youngest group. The majority of 15–19 year-olds have never been tested — ever.",
  "str_2039": "<span class=\"big-num\" data-target=\"81\" data-suffix=\"%\">81%</span>\n          <span class=\"stat-desc\">of young <strong>men</strong> aged 15–19 never tested<br><em>Table 17.2, Rwanda DHS 2025</em></span>",
  "str_2040": "<span class=\"big-num\" data-target=\"74.5\" data-suffix=\"%\">74.5%</span>\n          <span class=\"stat-desc\">of young <strong>women</strong> aged 15–19 never tested<br><em>Table 17.1, Rwanda DHS 2025</em></span>",
  "str_2041": "📍 Rinda: discreet peer-delivered self-test kits. Legal for under-18s since Rwanda lowered consent age to 15.",
  "str_2042": "Gap 2: The Female Condom-Use Gap",
  "str_2043": "Distributing condoms doesn't work for poor, rural women — the barrier is power and negotiation, not access.",
  "str_2044": "<span class=\"big-num\" style=\"color:var(--blue)\">73.8%</span>\n          <span class=\"stat-desc\">of young <strong>men</strong> 15–24 use condoms in higher-risk sex<br><em>vs only <strong>47.4% of women</strong></em></span>",
  "str_2045": "<span class=\"big-num\" data-target=\"34.1\" data-suffix=\"%\">34.1%</span>\n          <span class=\"stat-desc\">condom use among women in <strong>lowest wealth quintile</strong><br><em>Table 16.1, Rwanda DHS 2025</em></span>",
  "str_2046": "📍 Rinda: audio-based Kinyarwanda negotiation roleplay modules.",
  "str_2047": "Gap 3: The Knowledge Gap",
  "str_2048": "Youth without education or internet access are structurally excluded from urban-focused prevention campaigns.",
  "str_2049": "<span class=\"big-num\" style=\"color:var(--gold)\" data-target=\"48.7\" data-suffix=\"%\">48.7%</span>\n          <span class=\"stat-desc\">HIV knowledge among <strong>rural young men</strong> 15–24</span>",
  "str_2050": "<span class=\"big-num\" style=\"color:var(--gold)\" data-target=\"32.4\" data-suffix=\"%\">32.4%</span>\n          <span class=\"stat-desc\">HIV knowledge among women with <strong>no formal education</strong></span>",
  "str_2051": "📍 Rinda: USSD *775# works on any basic phone — zero data needed.",
  "str_2052": "Gap 4: The Teenage Pregnancy Surge",
  "str_2053": "Pregnancy rates among adolescents are rising sharply between ages 15 and 19, driven by lack of modern contraceptive use.",
  "str_2054": "<span class=\"big-num\" style=\"color:var(--green)\">19.9%</span>\n          <span class=\"stat-desc\">of young women aged 19 have <strong>ever been pregnant</strong><br><em>Table 4, Rwanda DHS 2025</em></span>",
  "str_2055": "<span class=\"big-num\" style=\"color:var(--green)\">46.0%</span>\n          <span class=\"stat-desc\">of sexually active unmarried women use <strong>no method</strong><br><em>Table 6, Rwanda DHS 2025</em></span>",
  "str_2056": "📍 Rinda: Cycle trackers &amp; modern family planning education.",
  "str_2057": "Rwanda DHS 2025",
  "str_2058": "The Raw Evidence",
  "str_2059": "Directly sourced from official Rwanda 2025 DHS tables — the foundation of every Rinda feature.",
  "str_2060": "<button class=\"tab-btn active\" id=\"btn-knowledge\" role=\"tab\" aria-selected=\"true\" aria-controls=\"tab-knowledge\" onclick=\"switchTab('knowledge')\">📊 HIV Knowledge</button>\n      <button class=\"tab-btn\" id=\"btn-testing\" role=\"tab\" aria-selected=\"false\" aria-controls=\"tab-testing\" onclick=\"switchTab('testing')\">🔬 Prior Testing</button>\n      <button class=\"tab-btn\" id=\"btn-condom\" role=\"tab\" aria-selected=\"false\" aria-controls=\"tab-condom\" onclick=\"switchTab('condom')\">⚡ Condom Use</button>\n      <button class=\"tab-btn\" id=\"btn-pregnancy\" role=\"tab\" aria-selected=\"false\" aria-controls=\"tab-pregnancy\" onclick=\"switchTab('pregnancy')\">👶 Pregnancy (Table 4)</button>\n      <button class=\"tab-btn\" id=\"btn-contraception\" role=\"tab\" aria-selected=\"false\" aria-controls=\"tab-contraception\" onclick=\"switchTab('contraception')\">💊 Contraception (Table 6)</button>",
